create table dirkspzm32.lvs_fahrz_defekt_dispo_st (
    sid         varchar2(2 char) not null enable,
    firma_nr    number(2, 0) not null enable,
    res_id      number(*, 0) not null enable,
    defekt_date date not null enable,
    status      varchar2(2 char) not null enable
);

alter table dirkspzm32.lvs_fahrz_defekt_dispo_st
    add constraint pk_lvs_fahrz_defekt_dispo_st
        primary key ( res_id,
                      defekt_date,
                      firma_nr,
                      sid )
            using index enable;


